import random
import statistics

def task_func(LETTERS):
    # Create a dictionary with each letter as a key and a list of 3 random integers as values
    my_dict = {}
    for letter in LETTERS:
        my_dict[letter] = [random.randint(0, 9) for _ in range(3)]

    # Sort the items based on the mean of their values in descending order
    sorted_items = sorted(my_dict.items(), key=lambda x: statistics.mean(x[1]), reverse=True)

    # Create a new dictionary maintaining the sorted order
    sorted_dict = {}
    for item in sorted_items:
        sorted_dict[item[0]] = item[1]

    return sorted_dict

